#include <stdio.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    char buf[128];
    int code = 404;
    char *path = "/proc/42/status";
    int pid = 42;
    // ★ snprintf(buf, sizeof(buf), fmt, ...) — écrit au max sizeof(buf)-1 chars
    int n = snprintf(buf, sizeof(buf), "[ERR-%d] Not found: %s (pid=%d)", code, path, pid);
    if (n >= (int)sizeof(buf)) { // ★ n = chars VOULUS, pas écrits
        printf("TRONQUE\n");
    } else {
        printf("%s\n", buf);
    }
    char small[20];
    n = snprintf(small, sizeof(small), "pid=%d cmd=%s", pid, "very_long_name_here");
    printf("Tronque: %s\n", n >= (int)sizeof(small) ? "oui" : "non"); // ★ détection troncature
    return 0;
}

